package com.hospital.management.model;import java.time.*;import java.util.*;
/** Prescription header with safely initialized medicine items. */public class Prescription {private Long prescriptionId,patientId,doctorId,departmentId,appointmentId,medicalRecordId;private String patientNumber,patientName,doctorName,departmentName,notes,status;private LocalDate prescriptionDate,validUntil,appointmentDate;private List<PrescriptionItem>items=new ArrayList<>();private LocalDateTime createdAt,updatedAt;public Long getPrescriptionId(){return prescriptionId;}public void setPrescriptionId(Long v){prescriptionId=v;}public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public String getPatientNumber(){return patientNumber;}public void setPatientNumber(String v){patientNumber=v;}public String getPatientName(){return patientName;}public void setPatientName(String v){patientName=v;}public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public String getDoctorName(){return doctorName;}public void setDoctorName(String v){doctorName=v;}public Long getDepartmentId(){return departmentId;}public void setDepartmentId(Long v){departmentId=v;}public String getDepartmentName(){return departmentName;}public void setDepartmentName(String v){departmentName=v;}public Long getAppointmentId(){return appointmentId;}public void setAppointmentId(Long v){appointmentId=v;}public Long getMedicalRecordId(){return medicalRecordId;}public void setMedicalRecordId(Long v){medicalRecordId=v;}public LocalDate getPrescriptionDate(){return prescriptionDate;}public void setPrescriptionDate(LocalDate v){prescriptionDate=v;}public LocalDate getValidUntil(){return validUntil;}public void setValidUntil(LocalDate v){validUntil=v;}public LocalDate getAppointmentDate(){return appointmentDate;}public void setAppointmentDate(LocalDate v){appointmentDate=v;}public String getNotes(){return notes;}public void setNotes(String v){notes=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public List<PrescriptionItem>getItems(){return Collections.unmodifiableList(items);}public void setItems(List<PrescriptionItem>v){items=v==null?new ArrayList<>():new ArrayList<>(v);}public void addItem(PrescriptionItem v){items.add(v);}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}public int getItemCount(){return items.size();}public boolean equals(Object o){return this==o||(o instanceof Prescription p&&prescriptionId!=null&&prescriptionId.equals(p.prescriptionId));}public int hashCode(){return Objects.hashCode(prescriptionId);}public String toString(){return"Prescription{id="+prescriptionId+", medicalRecordId="+medicalRecordId+", status="+status+"}";}}
